mapper.select:
select task_id as taskId, instance_id as instanceId, task_name as taskName, instance_no as instanceNo, instance_title as instanceTitle, task_state as taskState, task_result as taskResult, assignee_name_snapshot as assigneeNameSnapshot, assigned_at as assignedAt, completed_at as completedAt from t_bpm_task where 1 = 1
and instance_no like concat('%', #{queryForm.instanceNo}, '%')
and instance_title like concat('%', #{queryForm.instanceTitle}, '%')
and task_state = #{queryForm.taskState}
and assignee_employee_id = #{queryForm.assigneeEmployeeId}
order by assigned_at desc, task_id desc
